parameters.jsCode:
const topic = $('Researcher Input').first().json.body.topic;
const raw = $json.response || '';
let queries;
try {
  const clean = raw.replace(/\u0060\u0060\u0060json|\u0060\u0060\u0060/g,'').trim();
  const parsed = JSON.parse(clean);
  queries = parsed.queries || [topic];
} catch(e) {
  queries = [topic];
}
return queries.map(q => ({json: {query: q, original_topic: topic}}));

const xml = $json.data;
const entries = [];
const entryMatches = xml.matchAll(/<entry>(.*?)<\/entry>/gs);
for (const match of entryMatches) {
  const entry = match[1];
  const getId = (tag) => { const m = entry.match(new RegExp('<' + tag + '[^>]*>(.*?)<\\/' + tag + '>', 's')); return m ? m[1].trim() : ''; };
  const rawId = getId('id');
  const arxivId = rawId.split('/abs/').pop();
  const title = getId('title').replace(/\s+/g,' ');
  const summary = getId('summary').replace(/\s+/g,' ');
  const published = getId('published');
  const authors = [...entry.matchAll(/<name>(.*?)<\/name>/g)].map(m=>m[1].trim());
  const pdfUrl = rawId.replace('/abs/','/pdf/') + '.pdf';
  const absUrl = rawId;
  const catMatch = entry.match(/primary_category term="([^"]+)"/);
  const primaryCat = catMatch ? catMatch[1] : '';
  entries.push({json: {arxiv_id: arxivId, title, abstract: summary, authors, published, pdf_url: pdfUrl, abs_url: absUrl, primary_category: primaryCat}});
}
return entries;

const u = $input.first().json;
const q = $('Researcher Question').first().json.body.question;
return [{ json: { question: q, answer: u.output || '', rag_used: u.rag_used, status: u.status || 'ok' } }];

const staticData = $getWorkflowStaticData('global');
const chatId = String($json.message.chat.id);
const userMessage = $json.message.text || '';
const userName = $json.message.from.first_name || 'User';

if (!staticData.conversations) staticData.conversations = {};
if (!staticData.conversations[chatId]) staticData.conversations[chatId] = [];

const history = staticData.conversations[chatId].slice(-20);

const systemPrompt = 'You are a smart, friendly AI research assistant called Research Bot. You ONLY help with academic research, scientific topics, and educational questions.';

const messages = [{ role: 'system', content: systemPrompt }];
for (const msg of history) { messages.push({ role: msg.role, content: msg.content }); }
messages.push({ role: 'user', content: userMessage });

return [{ json: { chat_id: chatId, user_name: userName, user_message: userMessage, messages_json: JSON.stringify(messages) }}];

const staticData = $getWorkflowStaticData('global');
const chatId = $('Load Memory').item.json.chat_id;
const userMessage = $('Load Memory').item.json.user_message;
const botResponse = $json.choices[0].message.content;

if (!staticData.conversations) staticData.conversations = {};
if (!staticData.conversations[chatId]) staticData.conversations[chatId] = [];

staticData.conversations[chatId].push({ role: 'user', content: userMessage });
staticData.conversations[chatId].push({ role: 'assistant', content: botResponse });

if (staticData.conversations[chatId].length > 40) { staticData.conversations[chatId] = staticData.conversations[chatId].slice(-40); }

return [{ json: { text: botResponse, chat_id: chatId }}];

let response = $json.text;
const chatId = $json.chat_id;
const maxLen = 4000;
response = response.replace(/\*/g, '').replace(/_/g, '').replace(/\u0060\u0060\u0060/g, '').replace(/\u0060/g, '');
if (response.length <= maxLen) { return [{ json: { text: response, chat_id: chatId } }]; }
const parts = [];
let current = '';
for (const para of response.split('\n\n')) {
  if ((current + '\n\n' + para).length > maxLen && current) { parts.push(current.trim()); current = para; }
  else { current = current ? current + '\n\n' + para : para; }
}
if (current.trim()) parts.push(current.trim());
return parts.map(t => ({ json: { text: t, chat_id: chatId } }));

const userMessage = $json.body.message || '';
const providedHistory = $json.body.history || [];

const systemPrompt = 'You are a smart, friendly AI research assistant called Research Bot. You ONLY help with academic research, scientific topics, and educational questions.

CAPABILITIES:
- Discuss academic and scientific topics in depth
- Help formulate research questions and hypotheses
- Suggest methodologies and research approaches
- Explain complex scientific concepts simply
- Brainstorm research ideas and provide feedback
- Remember ALL previous conversations with the user

CONTENT RESTRICTION (VERY IMPORTANT):
- You ONLY discuss academic, scientific, research, and educational topics
- If the user asks about NON-ACADEMIC topics like: sports results, match scores, football, entertainment, celebrities, gossip, politics, news, weather, cooking, games, music, movies, etc. - you MUST politely decline
- When declining, say something like: I am a research assistant specialized in academic topics only. I cannot help with this topic. Feel free to ask me about any research or scientific topic!
- NEVER answer non-academic questions no matter what

RULES:
1. ALWAYS respond in the SAME LANGUAGE as the user message
2. Be warm, friendly, and engaging
3. Use emojis to make responses lively
4. DO NOT use * or _ for formatting - use emojis and line breaks instead
5. Keep responses clear and well-structured
6. If you do not know something, say so honestly
7. Reference previous conversations when relevant
8. When the user greets you, greet them back warmly by name and remind them you are a research assistant';

const messages = [{ role: 'system', content: systemPrompt }];
for (const msg of providedHistory) { 
  if (msg.role && msg.content) {
    messages.push({ role: msg.role, content: msg.content }); 
  }
}
messages.push({ role: 'user', content: userMessage });

return [{ json: { user_message: userMessage, messages_json: JSON.stringify(messages) }}];

let botResponse = $json.choices[0].message.content;
botResponse = botResponse.replace(/\*/g, '').replace(/_/g, '').replace(/\u0060\u0060\u0060/g, '').replace(/\u0060/g, '');
return [{ json: { output: botResponse } }];
